@namespace Components
@implements IDisposable
@inject IAddressValidator AddressValidator

<h3>Shipping Information</h3>

<div class="form-group">
    <label>Name</label>
    <input @bind="Shipping.Name" @bind:event="oninput" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label>Address</label>
    <input @bind="Shipping.Address" @bind:event="oninput" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label>City</label>
    <input @bind="Shipping.City" @bind:event="oninput" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label>Zip Code</label>
    <input @bind="Shipping.ZipCode" @bind:event="oninput" disabled="@_isValidating" />
</div>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error">@_errorMessage</div>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;

    [Parameter]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task ValidateAndProceed()
    {
        _errorMessage = null;

        // Cancel any in-flight validation (e.g. user went back, changed fields, clicked Next again).
        CancelPendingValidation();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was intentionally cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

